const docs = [
  { title: "О компании DelAI", text: "DelAI - агентство автоматизации бизнес-процессов с помощью ИИ, n8n и чат-ботов. Делаем под ключ за 5-7 дней. Работаем с малым и средним бизнесом. Сайт delai.agency." },
  { title: "Продажи и работа с клиентами", text: "Направление продаж и клиентов: обработка входящих заявок и передача в CRM, автоматический follow-up клиентам, генерация коммерческих предложений, квалификация лидов через ИИ (горячий/тёплый/холодный), напоминания менеджерам о сделках, автоматические CRM-воронки." },
  { title: "Маркетинг и контент", text: "Направление маркетинга и контента: контент-план и автогенерация постов через ИИ, автопостинг в соцсети, ответы на комментарии, триггерные рассылки по email/WhatsApp/Telegram, сбор аналитики рекламы в единый дашборд, мониторинг упоминаний бренда." },
  { title: "E-commerce и маркетплейсы", text: "Направление e-commerce и маркетплейсов: генерация карточек товаров для Wildberries и Ozon, автоответы на отзывы покупателей, создание инфографики, генерация описаний товаров, мониторинг цен конкурентов, синхронизация остатков между площадками." },
  { title: "Документы и внутренние процессы", text: "Направление документов и процессов: генерация договоров, счетов и актов из шаблонов, автозаполнение Word данными из Excel, транскрибация совещаний в протокол, автоматические отчёты в Telegram и email, согласование документов по цепочке подписантов." },
  { title: "HR и работа с персоналом", text: "Направление HR: ИИ-скрининг резюме, бот первичного собеседования в Telegram, онбординг новых сотрудников, работа с самозанятыми (чеки, учёт выплат), табель учёта рабочего времени, напоминания сотрудникам о задачах." },
  { title: "Чат-боты и ИИ-ассистенты", text: "Направление чат-ботов и ассистентов: боты-консультанты для сайта (отвечают как менеджер), Telegram и WhatsApp боты для бизнеса, запись клиентов на услуги с интеграцией календаря, FAQ-боты для техподдержки, интеграция ботов с CRM, 1С и Google Sheets." },
  { title: "Как мы работаем", text: "Этапы работы DelAI: 1) квалификация - понимаем боль и что автоматизировать, 2) план и предложение, 3) согласование регламентов, 4) реализация MVP, 5) демонстрация результата, 6) запуск. После запуска - поддержка 30 дней." },
  { title: "Цены и стоимость", text: "Цены DelAI на сайте не публикуются - считаем индивидуально после короткого созвона или переписки под конкретную задачу. Простой workflow стоит от небольших сумм, комплексное внедрение дороже. Точную смету даём под задачу клиента." }
];
return docs.map((d) => ({ json: { title: d.title, text: d.text } }));
